{"path":"C:\Users\rajaj\Projects\1_Conversa\src\infrastructure\providers\fake-analysis.ts","content":"import type { MeetingAnalysisProvider, AnalyzeInput } from "../../modules/analysis/domain/provider";
import type { MeetingAnalysis } from "../../shared/validation/schemas";
import { randomUUID } from "node:crypto";

/**
 * Deterministic fake analysis provider for offline/demo usage.
 *
 * Goals:
 * - stable outputs for CI/tests
 * - evidence-backed extraction from transcript text
 * - avoid fabricating owners/dates when missing
 */
export class FakeAnalysisProvider implements MeetingAnalysisProvider {
  readonly name = "fake";

  async analyze(input: AnalyzeInput): Promise<MeetingAnalysis> {
    const text = input.transcriptContent;
    const lowered = text.toLowerCase();

    const now = new Date().toISOString();
    const decisions: MeetingAnalysis["decisions"] = [];
    const proposedActions: MeetingAnalysis["proposedActions"] = [];
    const risks: string[] = [];

    const topics = [
      "demo",
      "publication",
      "security",
      "deployment",
      "launch",
      "billing",
      "planning",
    ].filter((t) => lowered.includes(t));

    // ---- Decisions ----
    if (/pasted-transcript workflow.*primary public demo/i.test(text)) {
      decisions.push(makeDecision(input.meetingId, now, "Use pasted-transcript workflow as primary public demo path.", "This path is called the most reliable demo option in the discussion.", "...pasted-transcript workflow will be the primary public demo...", 0.94));
    }

    if (/publish the current prototype.*experimental-use warning/i.test(text)) {
      decisions.push(makeDecision(input.meetingId, now, "Publish with explicit experimental/prototype warning.", "The team agrees publication must include limitation disclosure.", "...publish the current prototype with an explicit experimental-use warning.", 0.9));
    }

    if (/production deployment.*blocked until authentication and durable persistence/i.test(text)) {
      decisions.push(makeDecision(input.meetingId, now, "Keep production deployment blocked until authentication and durable persistence are implemented.", "The conversation sets explicit production blockers.", "...production deployment must remain blocked until authentication and durable persistence...", 0.96));
    }

    if (/launch/i.test(text)) {
      decisions.push(makeDecision(input.meetingId, now, "Launch the beta on the 15th.", "Team consensus to ship beta.", "Team agreed to launch the beta on the 15th.", 0.9));
    }

    // ---- Risks ----
    if (/risk is that the vercel deployment may not match the latest github commit/i.test(text)) {
      risks.push("Vercel deployment traceability risk: deployed artifact may not match latest GitHub commit.");
    }
    if (/blocked until authentication and durable persistence/i.test(text)) {
      risks.push("Production risk: authentication and durable persistence are missing prerequisites.");
    }
    if (/defer/i.test(text)) {
      risks.push("Billing dependency may resurface post-beta.");
    }

    // ---- Actions ----
    const maya = text.match(/Maya:\s*I will verify .* by (\d{1,2}\s+[A-Za-z]+\s+\d{4})/i);
    if (maya) {
      proposedActions.push(makeAction(input.meetingId, now, {
        description: "Verify GitHub and Wiki navigation.",
        ownerName: "Maya",
        dueDate: isoFromHumanDate(maya[1]),
        priority: "MEDIUM",
        targetSystem: "INTERNAL",
        actionType: "VALIDATION",
        rationale: "Public surfaces must be validated before publication.",
        sourceEvidence: "Maya: I will verify the GitHub and Wiki navigation by ...",
        confidence: 0.93,
        riskLevel: "MEDIUM",
      }));
    }

    const priya = text.match(/Priya:\s*I will confirm the deployed commit and run the public smoke test by (\d{1,2}\s+[A-Za-z]+\s+\d{4})/i);
    if (priya) {
      proposedActions.push(makeAction(input.meetingId, now, {
        description: "Confirm deployed commit and run public smoke test.",
        ownerName: "Priya",
        dueDate: isoFromHumanDate(priya[1]),
        priority: "HIGH",
        targetSystem: "INTERNAL",
        actionType: "VALIDATION",
        rationale: "Deployment traceability and smoke validation gate publication readiness.",
        sourceEvidence: "Priya: I will confirm the deployed commit and run the public smoke test by ...",
        confidence: 0.95,
        riskLevel: "HIGH",
      }));
    }

    if (/propose we approve publication after the link scan, security tests, and public demo all pass/i.test(text)) {
      proposedActions.push(makeAction(input.meetingId, now, {
        description: "Approve publication only after link scan, security tests, and public demo pass.",
        ownerName: "Daniel",
        dueDate: null,
        priority: "HIGH",
        targetSystem: "INTERNAL",
        actionType: "APPROVAL_GATE",
        rationale: "Publication should remain gated by objective checks.",
        sourceEvidence: "Daniel: I propose we approve publication after the link scan, security tests, and public demo all pass.",
        confidence: 0.92,
        riskLevel: "HIGH",
      }));
    }

    // Backward-compatible launch/rfc/defer extraction used by existing tests.
    const ownerMatch = text.match(/([A-Z][a-z]+)\s+owns? the launch/i);
    if (/launch/i.test(text)) {
      proposedActions.push(makeAction(input.meetingId, now, {
        description: "Complete the beta launch checklist.",
        ownerName: ownerMatch ? (ownerMatch[1] ?? null) : null,
        dueDate: /15th/.test(text) ? isoForDay(15) : null,
        priority: "HIGH",
        targetSystem: "INTERNAL",
        actionType: "TASK",
        rationale: "Required for beta launch.",
        sourceEvidence: "Team agreed to launch the beta on the 15th.",
        confidence: 0.85,
        riskLevel: "MEDIUM",
      }));
    }

    const rfcOwner = text.match(/([A-Z][a-z]+)\s+will draft the RFC/i);
    if (/rfc/i.test(text)) {
      proposedActions.push(makeAction(input.meetingId, now, {
        description: "Draft the integration RFC.",
        ownerName: rfcOwner ? (rfcOwner[1] ?? null) : null,
        dueDate: /friday/i.test(text) ? isoForWeekday(5) : null,
        priority: "MEDIUM",
        targetSystem: "INTERNAL",
        actionType: "DOC",
        rationale: "Needed before integration work.",
        sourceEvidence: "Rajeev will draft the RFC by Friday.",
        confidence: 0.8,
        riskLevel: "LOW",
      }));
    }

    if (/defer/i.test(text)) {
      proposedActions.push(makeAction(input.meetingId, now, {
        description: "Defer billing integration to next quarter.",
        ownerName: null,
        dueDate: null,
        priority: "LOW",
        targetSystem: "INTERNAL",
        actionType: "DECISION",
        rationale: "Reduce scope for beta.",
        sourceEvidence: "We decided to defer the billing integration.",
        confidence: 0.7,
        riskLevel: "LOW",
      }));
    }

    const summary = buildSummary(decisions, risks, proposedActions);

    return {
      id: randomUUID(),
      meetingId: input.meetingId,
      summary,
      topics,
      decisions,
      proposedActions,
      risks,
      createdAt: now,
    };
  }
}

export class FailingAnalysisProvider implements MeetingAnalysisProvider {
  readonly name = "fake-failing";

  async analyze(_input: AnalyzeInput): Promise<MeetingAnalysis> {
    throw new Error("analysis provider unavailable");
  }
}

function makeDecision(meetingId: string, now: string, description: string, rationale: string, sourceEvidence: string, confidence: number) {
  return {
    id: randomUUID(),
    meetingId,
    description,
    rationale,
    sourceEvidence,
    confidence,
    createdAt: now,
  };
}

type ActionSeed = {
  description: string;
  ownerName: string | null;
  dueDate: string | null;
  priority: "HIGH" | "MEDIUM" | "LOW";
  targetSystem: string;
  actionType: string;
  rationale: string;
  sourceEvidence: string;
  confidence: number;
  riskLevel: "HIGH" | "MEDIUM" | "LOW";
};

function makeAction(meetingId: string, now: string, seed: ActionSeed) {
  return {
    id: randomUUID(),
    meetingId,
    description: seed.description,
    ownerName: seed.ownerName,
    ownerReference: null,
    dueDate: seed.dueDate,
    priority: seed.priority,
    targetSystem: seed.targetSystem,
    actionType: seed.actionType,
    rationale: seed.rationale,
    sourceEvidence: seed.sourceEvidence,
    confidence: seed.confidence,
    riskLevel: seed.riskLevel,
    status: "PROPOSED" as const,
    createdAt: now,
    updatedAt: now,
  };
}

function isoForDay(day: number): string {
  const d = new Date();
  d.setDate(day);
  d.setUTCHours(0, 0, 0, 0);
  return d.toISOString();
}

function isoForWeekday(dow: number): string {
  const d = new Date();
  const diff = (dow - d.getDay() + 7) % 7 || 7;
  d.setDate(d.getDate() + diff);
  d.setUTCHours(0, 0, 0, 0);
  return d.toISOString();
}

function isoFromHumanDate(value: string): string | null {
  const parsed = new Date(value + " UTC");
  if (Number.isNaN(parsed.getTime())) return null;
  parsed.setUTCHours(0, 0, 0, 0);
  return parsed.toISOString();
}

function buildSummary(decisions: Array<{ description: string }>, risks: string[], actions: Array<{ description: string }>): string {
  if (decisions.length === 0 && actions.length === 0) {
    return "Transcript reviewed; no high-confidence decisions or actions extracted.";
  }
  return `Extracted ${decisions.length} decision(s), ${actions.length} proposed action(s), and ${risks.length} risk(s).`;
}
"}

